mapper.update:
UPDATE evd_review_case
   SET status = #{status}, decided_at = #{decidedAt}
 WHERE tenant_id = #{tenantId}
   AND review_case_id = CAST(#{reviewCaseId} AS uuid)
   AND status = #{expectedStatus}

UPDATE evd_review_case
   SET status = 'REOPENED'
 WHERE tenant_id = #{tenantId}
   AND review_case_id = CAST(#{reviewCaseId} AS uuid)
   AND status = #{expectedStatus}

mapper.select:
SELECT review_case_id::text
  FROM evd_review_case
 WHERE tenant_id = #{tenantId}
   AND origin = 'CLIENT'
   AND external_submission_ref = #{externalSubmissionRef}

SELECT result_id::text
  FROM evd_review_command_result
 WHERE tenant_id = #{tenantId}
   AND operation_type = #{operationType}
   AND idempotency_key = #{idempotencyKey}
